public class HighFrequencyDictionary implements Dictionary {
  private IndexReader reader;
  private String field;
  private float thresh;

  public HighFrequencyDictionary(IndexReader reader, String field, float thresh) {
    this.reader = reader;
    this.field = StringHelper.intern(field);
    this.thresh = thresh;
  }

  public final Iterator getWordsIterator() {
    return new HighFrequencyIterator();
  }

  final class HighFrequencyIterator implements Iterator {
    private TermsEnum termsEnum;
    private BytesRef actualTerm;
    private boolean hasNextCalled;
    private int minNumDocs;

    HighFrequencyIterator() {
      try {
        Terms terms = MultiFields.getTerms(reader, field);
        if (terms != null) {
          termsEnum = terms.iterator();
        }
        minNumDocs = (int)(thresh * (float)reader.numDocs());
      } catch (IOException e) {
        throw new RuntimeException(e);
      }
    }

    private boolean isFrequent(int freq) {
      return freq >= minNumDocs;
    }

    public Object next() {
      if (!hasNextCalled && !hasNext()) {
        return null;
      }
      hasNextCalled = false;

      return (actualTerm != null) ? actualTerm.utf8ToString() : null;
    }

    public boolean hasNext() {
      if (hasNextCalled) {
        return actualTerm != null;
      }
      hasNextCalled = true;

      if (termsEnum == null) {
        return false;
      }

      while(true) {

        try {
          actualTerm = termsEnum.next();
        } catch (IOException e) {
          throw new RuntimeException(e);
        }

        // if there are no words return false
        if (actualTerm == null) {
          return false;
        }

        // got a valid term, does it pass the threshold?
        if (isFrequent(termsEnum.docFreq())) {
          return true;
        }
      }
    }

    public void remove() {
      throw new UnsupportedOperationException();
    }
  }
}
